// // This is a 4-bit shift register with a clock input (clk), a serial input (sin), and a 4-bit output (q). However, the shift operation is performed on the least significant bit instead of the most significant bit.
module shift_register (
    input clk,
    input sin,
    output [3:0] q
);

    reg [3:0] q_reg;

    always @(posedge clk) begin
        q_reg <= {q_reg[2:0], sin};
    end

    assign q = q_reg;

endmodule
